sql:
SELECT domain_id, AVG(average_session_duration) AS avg_session_duration
FROM traffic_metrics
GROUP BY domain_id;

external_knowledge:
- "thriving" refers to campaigns that are active and have active domains;
- "vitality of user engagement" is measured by the average session duration;
- "longest average session durations" indicates the campaigns with the highest average session durations.

- 'Blossoms' refer to domains;
- 'Thriving' refers to domains with an active status;
- 'Watered with user consent' means the user has given consent;
- 'Highest average bounce rates' indicates the domains with the greatest proportion of visitors leaving the site without interacting further;
- 'Top 10' means the query returns the 10 domains with the highest average bounce rates.

sql:
SELECT COUNT(DISTINCT domain_id) 
FROM domains 
WHERE traffic_source = 'organic';

SELECT COUNT(DISTINCT domain_id) AS total_unique_domains
FROM traffic_metrics
WHERE date BETWEEN '2023-05-01' AND '2023-05-31';

external_knowledge:
