sql:
SELECT COUNT(cookie_id) 
FROM user_consent 
WHERE user_id = 1 AND consent_given = 0;

SELECT COUNT(DISTINCT user_id) 
FROM user_consent 
WHERE consent_given = 1;

external_knowledge:
